import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './UserAddress.css';

const UserAddress = ({ userId }) => {
    const [show, setShow] = useState(false);
    const [savedAddresses, setSavedAddresses] = useState([]);
    const [formData, setFormData] = useState({
        AddressLine1: '',
        AddressLine2: '',
        AddressLine3: '',
        postalCode: '',
        city: '',
        country: '',
        isDefault: false
    });
    const [editId, setEditId] = useState(null);

    useEffect(() => {
        fetchAddresses();
    }, [userId]);

    const fetchAddresses = async () => {
        try {
            const response = await axios.get(`/api/users/${userId}`);
            setSavedAddresses(response.data.user.addresses);
        } catch (err) {
            console.error("Failed to fetch addresses", err);
        }
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            [name]: value,
        });
    };

    const handleSaveAddress = async () => {
        try {
            if (editId) {
                await axios.put(`/api/users/${userId}/addresses/${editId}`, formData);
            } else {
                await axios.post(`/api/users/${userId}/addresses`, formData);
            }
            fetchAddresses();
            setShow(false);
            setFormData({
                AddressLine1: '',
                AddressLine2: '',
                AddressLine3: '',
                postalCode: '',
                city: '',
                country: '',
                isDefault: false
            });
            setEditId(null);
        } catch (err) {
            console.error("Failed to save address", err);
        }
    };

    const handleDeleteAddress = async (id) => {
        try {
            await axios.delete(`/api/users/${userId}/addresses/${id}`);
            fetchAddresses();
        } catch (err) {
            console.error("Failed to delete address", err);
        }
    };

    const handleEditAddress = (address) => {
        setFormData(address);
        setEditId(address._id);
        setShow(true);
    };

    return (
        <div className='useraddress'>
            {/* Render the address list and form */}
            {/* ... (same as before) ... */}
        </div>
    );
};

export default UserAddress;
